theme.stylesheet:
/* ── Window frame: faked Aero glass ─────────────────────────────────────── */
[data-theme="win7"] [data-part="window"] {
  /* White sheen over the translucent blue frame sells the glass. */
  background:
    radial-gradient(130% 70% at 28% 0%, rgba(255, 255, 255, 0.42), rgba(255, 255, 255, 0) 62%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.28) 0%, rgba(255, 255, 255, 0) 45%),
    var(--window-bg);
  /* --window-shadow carries the 1px inner white highlight; the native
     borderless NSWindow draws the actual drop shadow. */
  box-shadow: var(--window-shadow);
}

[data-theme="win7"] [data-part="window"][data-focused="false"] {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.3) 0%, rgba(255, 255, 255, 0) 50%),
    var(--x-win7-frame-inactive);
}

/* Client area sits inside the 6px glass frame, ringed by the dark client
   edge plus the Aero white hairline just outside it. */
[data-theme="win7"] [data-part="window-body"] {
  margin: 0 var(--window-frame-w) var(--window-frame-w);
  background: linear-gradient(180deg, #f4f6f8 0%, #ebeef1 100%);
  border: 1px solid var(--x-win7-client-edge);
  box-shadow: 0 0 0 1px var(--x-win7-inner-highlight);
}

/* ── Titlebar ───────────────────────────────────────────────────────────── */
[data-theme="win7"] [data-part="titlebar"] {
  background: var(--titlebar-bg);
}

[data-theme="win7"] [data-part="window"][data-focused="false"] [data-part="titlebar"] {
  background: var(--titlebar-bg-inactive);
}

[data-theme="win7"] [data-part="title"] {
  /* Segoe UI with the signature white glow (alignment is chrome.titleAlign). */
  padding: 0 8px;
  font-size: 13px;
  color: var(--titlebar-fg);
  text-shadow: var(--x-win7-title-glow);
}

[data-theme="win7"] [data-part="window"][data-focused="false"] [data-part="title"] {
  color: var(--titlebar-fg-inactive);
  text-shadow: var(--x-win7-title-glow-inactive);
}

[data-theme="win7"] [data-part="title-icon"] {
  margin-left: 9px;
}

/* ── Caption buttons: one connected glass pill, hung from the top edge ──── */
[data-theme="win7"] [data-part="controls"] {
  align-self: flex-start;
  margin: 0 var(--window-frame-w) 0 10px;
}

[data-theme="win7"] [data-part="control"] {
  width: 30px;
  height: 19px;
  /* Shared 1px outline between neighbors; no top border — the group reads
     as attached to the window's own top edge. */
  margin-left: -1px;
  border: 1px solid var(--x-win7-caption-border);
  border-top: none;
  background:
    linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.55) 0%,
      rgba(255, 255, 255, 0.2) 45%,
      rgba(112, 134, 156, 0.22) 50%,
      rgba(255, 255, 255, 0.22) 100%
    );
  /* A bright 1px inner ring just inside the dark caption border — the glass
     "thickness" that makes the buttons read as real Aero (not a flat dark
     outline). The brighter top keeps the glossy top sheen. */
  box-shadow:
    inset 0 1px 0 var(--x-win7-inner-highlight),
    inset 0 0 0 1px rgba(255, 255, 255, 0.4);
  /* Caption glyphs stay white-on-glass; --titlebar-fg is the (dark) caption
     text, so the buttons pin their own color. */
  color: var(--x-win7-caption-glyph);
  transition: background var(--motion-fast) var(--ease);
}

[data-theme="win7"] [data-part="control"] svg {
  filter: drop-shadow(0 1px 1px rgba(8, 24, 44, 0.7));
}

/* Outer bottom corners only — the pill shape. Order is fixed by the theme's
   chrome config (minimize · zoom · close), so per-action rounding is safe. */
[data-theme="win7"] [data-part="control"][data-action="minimize"] {
  margin-left: 0;
  border-bottom-left-radius: 4px;
}
[data-theme="win7"] [data-part="control"][data-action="close"] {
  width: 46px;
  border-bottom-right-radius: 4px;
}

/* Focused close: the solid Aero red — a glossy fill with a bright top half and
   a darker bottom half (a white sheen over a top-light → bottom-dark red base).
   Only when the window is key; the unfocused look stays the pale glass below.
   :hover / :active (later) still brighten/press it. */
[data-theme="win7"] [data-part="control"][data-action="close"][data-focused="true"] {
  background:
    linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.5) 0%,
      rgba(255, 255, 255, 0.12) 46%,
      rgba(255, 255, 255, 0) 52%,
      rgba(255, 255, 255, 0.1) 100%
    ),
    linear-gradient(180deg, #ec6a5f 0%, #d6463c 49%, #bf3830 51%, #a62820 100%);
  color: var(--x-win7-caption-glyph);
}

/* Inactive window: the glass goes pale and the glyphs dim. */
[data-theme="win7"] [data-part="control"][data-focused="false"] {
  background:
    linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.42) 0%,
      rgba(238, 242, 246, 0.18) 48%,
      rgba(202, 210, 218, 0.2) 52%,
      rgba(255, 255, 255, 0.18) 100%
    );
  color: var(--x-win7-caption-glyph-inactive);
}

/* Hover lifts the SAME glass — brighter, with an Aero-blue lower half — keeping
   the convex top-light/bottom-dark form. (Not a bottom-centered glow, which
   read as the button caving in.) */
[data-theme="win7"] [data-part="control"]:hover {
  background:
    linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.88) 0%,
      rgba(235, 246, 253, 0.55) 45%,
      rgba(150, 201, 237, 0.5) 50%,
      rgba(200, 230, 250, 0.55) 100%
    );
  color: var(--x-win7-caption-glyph);
}

/* Close hover: the same red glass, just brighter. */
[data-theme="win7"] [data-part="control"][data-action="close"]:hover {
  background:
    linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.6) 0%,
      rgba(255, 255, 255, 0.2) 46%,
      rgba(255, 255, 255, 0) 52%,
      rgba(255, 255, 255, 0.16) 100%
    ),
    linear-gradient(180deg, #ff8e80 0%, #f0604f 49%, #dd463b 51%, #c4352c 100%);
}

/* Pressed: the same glass, darker, sunk in with an inset shadow (a press DOES
   recess — that's where a darker, inset look belongs, not on hover). */
[data-theme="win7"] [data-part="control"]:active {
  background:
    linear-gradient(
      180deg,
      rgba(176, 201, 223, 0.75) 0%,
      rgba(150, 180, 206, 0.55) 50%,
      rgba(124, 154, 183, 0.55) 100%
    );
  box-shadow: inset 0 1px 3px rgba(8, 24, 44, 0.55);
}

[data-theme="win7"] [data-part="control"][data-action="close"]:active {
  background: linear-gradient(180deg, #c4453a 0%, #a52c23 50%, #891c17 100%);
  box-shadow: inset 0 1px 3px rgba(40, 0, 0, 0.6);
}

/* ── Toolbar: the Explorer command bar ──────────────────────────────────── */
[data-theme="win7"] [data-part="toolbar"] {
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--toolbar-border);
}

[data-theme="win7"] [data-part="toolbar-button"] {
  min-height: 26px;
  padding: 3px 10px;
  border: 1px solid transparent;
  border-radius: 3px;
  color: var(--control-fg);
}

[data-theme="win7"] [data-part="toolbar-button"]:hover {
  background: var(--control-bg-hover);
  border-color: var(--x-win7-hover-border);
  box-shadow: inset 0 0 0 1px var(--x-win7-inner-highlight);
}

[data-theme="win7"] [data-part="toolbar-button"]:active,
[data-theme="win7"] [data-part="toolbar-button"][data-state="active"] {
  background: var(--control-bg-active);
  border-color: var(--x-win7-pressed-border);
  box-shadow: inset 0 1px 2px rgba(8, 40, 70, 0.3);
}

/* ── Breadcrumbs: the Win7 address bar ──────────────────────────────────── */
[data-theme="win7"] [data-part="breadcrumbs"] {
  flex: 1;
  height: 26px;
  padding: 0 2px;
  background: var(--input-bg);
  border: 1px solid var(--input-border);
  border-radius: var(--input-radius);
}

[data-theme="win7"] [data-part="breadcrumbs"] svg {
  color: var(--fg-muted);
}

[data-theme="win7"] [data-part="breadcrumb"] {
  height: 20px;
  padding: 0 7px;
  border: 1px solid transparent;
  border-radius: 2px;
  color: var(--fg);
}

[data-theme="win7"] [data-part="breadcrumb"]:hover {
  background: var(--control-bg-hover);
  border-color: var(--x-win7-hover-border);
}

[data-theme="win7"] [data-part="breadcrumb"]:active {
  background: var(--control-bg-active);
  border-color: var(--x-win7-pressed-border);
}

/* ── Search field ───────────────────────────────────────────────────────── */
[data-theme="win7"] [data-part="search-field"] {
  height: 26px;
  padding: 0 7px;
  background: var(--input-bg);
  border: 1px solid var(--input-border);
  border-radius: var(--input-radius);
  color: var(--input-fg);
}

[data-theme="win7"] [data-part="search-field"] svg {
  color: var(--fg-muted);
}

[data-theme="win7"] [data-part="search-field"] input::placeholder {
  /* Win7 search boxes show their hint in italic gray. */
  color: var(--fg-disabled);
  font-style: italic;
}

/* ── Generic Aero buttons ───────────────────────────────────────────────── */
[data-theme="win7"] [data-part="button"],
[data-theme="win7"] [data-part="icon-button"],
[data-theme="win7"] [data-part="segment"] {
  min-height: 23px;
  padding: 2px 12px;
  background: var(--control-bg);
  border: 1px solid var(--control-border);
  border-radius: var(--control-radius);
  box-shadow: var(--control-shadow);
  color: var(--control-fg);
  transition: background var(--motion-fast) var(--ease), border-color var(--motion-fast) var(--ease);
}

[data-theme="win7"] [data-part="icon-button"] {
  padding: 2px 6px;
}

[data-theme="win7"] [data-part="button"]:hover,
[data-theme="win7"] [data-part="icon-button"]:hover,
[data-theme="win7"] [data-part="segment"]:hover {
  background: var(--control-bg-hover);
  border-color: var(--x-win7-hover-border);
}

[data-theme="win7"] [data-part="button"]:active,
[data-theme="win7"] [data-part="icon-button"]:active,
[data-theme="win7"] [data-part="segment"]:active,
[data-theme="win7"] [data-part="segment"][data-state="selected"] {
  background: var(--control-bg-active);
  border-color: var(--x-win7-pressed-border);
  box-shadow: inset 0 1px 2px rgba(8, 40, 70, 0.3);
}

/* Segments join into one control, sharing the 1px border. */
[data-theme="win7"] [data-part="segment"] {
  margin-left: -1px;
  border-radius: 0;
}
[data-theme="win7"] [data-part="segment"]:first-child {
  margin-left: 0;
  border-radius: var(--control-radius) 0 0 var(--control-radius);
}
[data-theme="win7"] [data-part="segment"]:last-child {
  border-radius: 0 var(--control-radius) var(--control-radius) 0;
}

/* ── Sidebar: the Explorer navigation pane ──────────────────────────────── */
[data-theme="win7"] [data-part="sidebar"] {
  background: var(--sidebar-bg);
  padding-top: 4px;
}

[data-theme="win7"] [data-part="sidebar-heading"] {
  padding: 8px 10px 3px;
  font-size: 12px;
  color: var(--fg-muted);
}

[data-theme="win7"] [data-part="sidebar-item"] {
  width: calc(100% - 8px);
  margin: 0 4px;
  padding: 0 4px 0 12px;
  border-radius: 2px;
  color: var(--sidebar-fg);
}

[data-theme="win7"] [data-part="sidebar-item-icon"] {
  color: var(--fg-muted);
}

[data-theme="win7"] [data-part="sidebar-item"]:hover {
  background: var(--x-win7-hover-bg);
  box-shadow: inset 0 0 0 1px var(--x-win7-hover-border-soft);
}

[data-theme="win7"] [data-part="sidebar-item"][data-state="selected"] {
  background: var(--sidebar-selected-bg);
  box-shadow: inset 0 0 0 1px var(--x-win7-sel-border-soft);
  color: var(--sidebar-selected-fg);
}

/* Inline eject on removable-volume rows — the tab-close treatment. */
[data-theme="win7"] [data-part="sidebar-item-action"] {
  width: 15px;
  height: 15px;
  border-radius: 3px;
  color: var(--fg-muted);
}

[data-theme="win7"] [data-part="sidebar-item-action"]:hover {
  background: linear-gradient(#fdfdfd, #e5f1fb);
  box-shadow: inset 0 0 0 1px #8e9cad;
  color: var(--fg);
}

[data-theme="win7"] [data-part="sidebar-item"][data-state="selected"] [data-part="sidebar-item-action"] {
  color: var(--sidebar-selected-fg);
}

/* ── Split divider ──────────────────────────────────────────────────────── */
[data-theme="win7"] [data-part="split-divider"] {
  background: linear-gradient(
    90deg,
    transparent calc(50% - 0.5px),
    var(--toolbar-border) calc(50% - 0.5px),
    var(--toolbar-border) calc(50% + 0.5px),
    transparent calc(50% + 0.5px)
  );
}

/* ── File list ──────────────────────────────────────────────────────────── */
[data-theme="win7"] [data-part="file-list"] {
  background: var(--list-bg);
}

[data-theme="win7"] [data-part="file-list-header"] {
  background: var(--list-header-bg);
  border-bottom: 1px solid var(--border);
  color: var(--list-header-fg);
  font-size: 12px;
}

[data-theme="win7"] [data-part="file-list-col"] {
  height: 100%;
  display: flex;
  align-items: center;
  border-right: 1px solid var(--border);
}
[data-theme="win7"] [data-part="file-list-col"][data-col="size"] {
  justify-content: flex-end;
}

/* Column-header hover: the white-to-blue Aero wash. */
[data-theme="win7"] [data-part="file-list-col"]:hover {
  background: linear-gradient(180deg, #f4f9fd 0%, #dceefb 100%);
}

[data-theme="win7"] [data-part="file-row"] {
  border-radius: 2px;
  font-size: 12px;
}

[data-theme="win7"] [data-part="file-row"][data-zebra="even"] {
  background: var(--list-zebra);
}

[data-theme="win7"] [data-part="file-row"]:hover {
  background: var(--x-win7-hover-bg);
  box-shadow: inset 0 0 0 1px var(--x-win7-hover-border-soft);
}

[data-theme="win7"] [data-part="file-row"][data-state="selected"] {
  background: var(--x-win7-sel-bg);
  box-shadow: inset 0 0 0 1px var(--x-win7-sel-border);
  color: var(--selection-fg);
}

/* Unfocused window: selection falls back to the flat gray Win7 uses. */
[data-theme="win7"]
  [data-part="window"][data-focused="false"]
  [data-part="file-row"][data-state="selected"] {
  background: var(--surface);
  box-shadow: inset 0 0 0 1px var(--border);
}

[data-theme="win7"] [data-part="file-cell"][data-col="date"],
[data-theme="win7"] [data-part="file-cell"][data-col="size"],
[data-theme="win7"] [data-part="file-cell"][data-col="kind"] {
  color: var(--fg-muted);
}

/* ── Icon grid: glassy selection plate, like Explorer's icon view ────────── */
[data-theme="win7"] [data-part="icon-grid"] {
  background: var(--list-bg);
}
[data-theme="win7"] [data-part="icon-grid-item"] {
  border: 1px solid transparent;
  border-radius: 3px;
}
[data-theme="win7"] [data-part="icon-grid-item"]:hover {
  background: var(--x-win7-row-hover, rgba(229, 243, 251, 0.6));
}
[data-theme="win7"] [data-part="icon-grid-item"][data-state="selected"] {
  background: var(--x-win7-sel-bg);
  border-color: var(--x-win7-sel-border);
}

[data-theme="win7"] [data-part="list-empty"] {
  color: var(--fg-muted);
}

/* ── Terminal: cmd.exe ──────────────────────────────────────────────────── */
[data-theme="win7"] [data-part="terminal-panel"] {
  /* Chrome surface, not terminal black: the resize grip + header are window
     chrome; only the host paints the terminal background. */
  background: var(--surface);
  border-top: 1px solid var(--x-win7-client-edge);
}

[data-theme="win7"] [data-part="terminal-header"] {
  height: 26px;
  padding: 0 8px;
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--toolbar-border);
  font-size: 12px;
  color: var(--fg-muted);
}

[data-theme="win7"] [data-part="terminal-host"] {
  background: var(--terminal-bg);
  color: var(--terminal-fg);
  font-family: var(--font-mono);
  padding: 4px 6px;
}

/* ── Status bar: the details-pane blue wash ─────────────────────────────── */
[data-theme="win7"] [data-part="status-bar"] {
  height: 26px;
  background: linear-gradient(180deg, #f2f7fc 0%, #e0ebf6 100%);
  border-top: 1px solid var(--toolbar-border);
  font-size: 12px;
  color: var(--fg-muted);
}

/* ── Menus ──────────────────────────────────────────────────────────────── */
[data-theme="win7"] [data-part="menu"] {
  padding: 2px;
  background: var(--bg);
  border: 1px solid var(--border-strong);
  box-shadow: 0 3px 10px rgba(0, 0, 0, 0.35);
}

[data-theme="win7"] [data-part="menu-item"] {
  height: 22px;
  padding: 0 18px 0 8px;
  border-radius: 2px;
  color: var(--fg);
}

[data-theme="win7"] [data-part="menu-item"]:hover {
  background: var(--x-win7-hover-bg);
  box-shadow: inset 0 0 0 1px var(--x-win7-menu-hover-border);
}

[data-theme="win7"] [data-part="menu-separator"] {
  height: 1px;
  margin: 3px 1px;
  background: var(--border);
}

/* ── Scrollbars: slim light-gray rounded thumbs in a flat track ─────────── */
[data-theme="win7"] ::-webkit-scrollbar-thumb {
  border-radius: 7px;
  /* Track-colored border + padding-box clip floats the rounded thumb. */
  border: 3px solid var(--scrollbar-track);
  background-clip: padding-box;
}

[data-theme="win7"] ::-webkit-scrollbar-thumb:hover {
  background-color: var(--fg-disabled);
}

/* ── In-page tabs (⌘T) — IE8-style document tabs on a soft Aero wash ────── */
[data-theme="win7"] [data-part="tab-bar"] {
  background: linear-gradient(180deg, #eef3f9 0%, #dce7f3 100%);
  border-bottom: 1px solid var(--toolbar-border);
  padding: 4px 6px 0;
  gap: 2px;
}

[data-theme="win7"] [data-part="tab"] {
  height: 24px;
  min-height: 24px;
  font-size: 12px;
  color: var(--fg);
  border: 1px solid #8e9cad;
  border-bottom: none;
  border-radius: 3px 3px 0 0;
  /* The Aero glass split: bright top half, dimmer bottom half. */
  background: linear-gradient(#f5f8fb, #e8eef5 50%, #d8e2ee 50%, #e4ecf5);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.8);
}

[data-theme="win7"] [data-part="tab"]:hover {
  background: linear-gradient(#fbfdfe, #f0f6fb 50%, #e2ecf6 50%, #ecf4fb);
}

[data-theme="win7"] [data-part="tab"][data-state="selected"] {
  background: linear-gradient(#ffffff, #f6fafd 50%, #ecf3fa 50%, #f8fbfe);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.95),
    0 1px 0 rgba(255, 255, 255, 0.9);
}

[data-theme="win7"] [data-part="tab-label"] {
  text-align: center;
}

[data-theme="win7"] [data-part="tab-close"],
[data-theme="win7"] [data-part="tab-add"] {
  width: 15px;
  height: 15px;
  border-radius: 3px;
  font-size: 12px;
  line-height: 1;
  color: var(--fg-muted);
}

[data-theme="win7"] [data-part="tab-close"]:hover,
[data-theme="win7"] [data-part="tab-add"]:hover {
  background: linear-gradient(#fdfdfd, #e5f1fb);
  box-shadow: inset 0 0 0 1px #8e9cad;
  color: var(--fg);
}

[data-theme="win7"] [data-part="tab-add"] {
  align-self: center;
  margin: 0 3px 4px;
}

/* ── Modal dialogs: the Aero task dialog — white body, gray command row ──── */
[data-theme="win7"] [data-part="dialog-overlay"] {
  background: rgba(0, 0, 0, 0.15);
}

[data-theme="win7"] [data-part="dialog"] {
  background: #ffffff;
  border: 1px solid rgba(28, 48, 70, 0.7);
  border-radius: 6px;
  padding: 0;
  gap: 0;
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.6), 0 14px 40px rgba(0, 0, 0, 0.45);
  overflow: hidden;
}

[data-theme="win7"] [data-part="dialog-title"] {
  /* Win7's "main instruction" line: large, blue, no caption strip. */
  color: #003399;
  font-size: 15px;
  font-weight: 400;
  padding: 14px 16px 6px;
}

[data-theme="win7"] [data-part="dialog-body"] {
  padding: 4px 16px 14px;
}

[data-theme="win7"] [data-part="dialog-actions"] {
  background: linear-gradient(180deg, #f6f6f6, #efefef);
  border-top: 1px solid #dfdfdf;
  padding: 10px 16px;
}

[data-theme="win7"] [data-part="text-input"] {
  background: #ffffff;
  border: 1px solid #abadb3;
  border-radius: 2px;
  padding: 4px 6px;
}
